package ir.tahamohamadi.publication; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="publication_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class PublicationTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="publication_id",nullable=false) private Publication publication; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String title; @Column(nullable=false) private String slug; @Column(name="abstract_text",columnDefinition="text") private String abstractText; @Column(name="authors_display",columnDefinition="text") private String authorsDisplay; @Column(name="venue_display",columnDefinition="text") private String venueDisplay; @Column(name="seo_title") private String seoTitle; @Column(name="seo_description") private String seoDescription; }
